import React, { useState, useEffect, useCallback } from 'react';
import GameShell from '../GameShell';
import { GameType } from '../../types';

interface MemoryMatrixProps {
  onGameOver: (score: number) => void;
  onExit: () => void;
}

const MemoryMatrix: React.FC<MemoryMatrixProps> = ({ onGameOver, onExit }) => {
  const [level, setLevel] = useState(1);
  const [gridSize, setGridSize] = useState(3);
  const [targetTiles, setTargetTiles] = useState<number[]>([]);
  const [selectedTiles, setSelectedTiles] = useState<number[]>([]);
  const [gameState, setGameState] = useState<'WATCH' | 'RECALL' | 'SUCCESS' | 'FAIL'>('WATCH');
  const [lives, setLives] = useState(3);

  // Generate new level
  const generateLevel = useCallback(() => {
    const totalTiles = gridSize * gridSize;
    const numTargets = Math.min(Math.floor(level / 2) + 2, totalTiles - 1);
    const newTargets = new Set<number>();

    while(newTargets.size < numTargets) {
      newTargets.add(Math.floor(Math.random() * totalTiles));
    }

    setTargetTiles(Array.from(newTargets));
    setSelectedTiles([]);
    setGameState('WATCH');
  }, [level, gridSize]);

  // Initial load
  useEffect(() => {
    generateLevel();
  }, [generateLevel]);

  // Watch timer
  useEffect(() => {
    if (gameState === 'WATCH') {
      const timer = setTimeout(() => {
        setGameState('RECALL');
      }, 1500 + (level * 200)); // More time for higher levels
      return () => clearTimeout(timer);
    }
  }, [gameState, level]);

  const handleTileClick = (index: number) => {
    if (gameState !== 'RECALL') return;

    // Toggle selection
    if (selectedTiles.includes(index)) return; // Can't unselect in this version for simplicity

    const newSelected = [...selectedTiles, index];
    setSelectedTiles(newSelected);

    // Check if correct
    if (!targetTiles.includes(index)) {
      // Wrong tile
      setLives(l => l - 1);
      setGameState('FAIL');
      setTimeout(() => {
        if (lives <= 1) {
          onGameOver(level * 100);
        } else {
          // Retry same level or regen? Let's regen to keep it fresh but easier
           generateLevel();
        }
      }, 1000);
    } else {
      // Correct tile check if all found
      const allFound = targetTiles.every(t => newSelected.includes(t));
      if (allFound) {
        setGameState('SUCCESS');
        setTimeout(() => {
          setLevel(l => l + 1);
          if (level % 3 === 0) setGridSize(s => Math.min(s + 1, 6)); // Increase grid size every 3 levels
        }, 1000);
      }
    }
  };

  // Effect to trigger next level generation after success delay
  useEffect(() => {
    if (gameState === 'SUCCESS') {
        const timer = setTimeout(() => {
            generateLevel();
        }, 800);
        return () => clearTimeout(timer);
    }
  }, [gameState, generateLevel]);


  return (
    <GameShell
      title="Matriz de Memória"
      description={gameState === 'WATCH' ? "Memorize o padrão azul" : "Toque nos quadrados que apareceram"}
      score={level * 100}
      onExit={onExit}
    >
      <div 
        className="grid gap-2 transition-all duration-300"
        style={{
          gridTemplateColumns: `repeat(${gridSize}, minmax(0, 1fr))`,
          width: '100%',
          maxWidth: '350px',
          aspectRatio: '1/1'
        }}
      >
        {Array.from({ length: gridSize * gridSize }).map((_, i) => {
          const isTarget = targetTiles.includes(i);
          const isSelected = selectedTiles.includes(i);

          let bgColor = 'bg-surface'; // Default

          if (gameState === 'WATCH' && isTarget) {
            bgColor = 'bg-primary shadow-[0_0_15px_rgba(99,102,241,0.5)] scale-95';
          } else if (gameState === 'RECALL' || gameState === 'SUCCESS' || gameState === 'FAIL') {
             if (isSelected && isTarget) bgColor = 'bg-success animate-bounce';
             else if (isSelected && !isTarget) bgColor = 'bg-red-500 animate-shake';
             else if (gameState === 'FAIL' && isTarget) bgColor = 'bg-primary/50'; // Reveal missed
          }

          return (
            <button
              key={i}
              onClick={() => handleTileClick(i)}
              disabled={gameState !== 'RECALL'}
              className={`
                rounded-lg transition-all duration-200 border border-white/5
                ${bgColor}
                ${gameState === 'RECALL' ? 'hover:bg-white/10 active:scale-95' : ''}
              `}
            />
          );
        })}
      </div>

      <div className="absolute bottom-8 flex gap-2">
        {Array.from({ length: 3 }).map((_, i) => (
          <div 
            key={i} 
            className={`w-3 h-3 rounded-full ${i < lives ? 'bg-red-500' : 'bg-gray-700'}`} 
          />
        ))}
      </div>
    </GameShell>
  );
};

export default MemoryMatrix;

import React, { useState, useEffect, useRef } from 'react';
import GameShell from '../GameShell';

interface ColorConflictProps {
  onGameOver: (score: number) => void;
  onExit: () => void;
}

const COLORS = [
  { name: 'VERMELHO', hex: '#ef4444' }, // Red
  { name: 'AZUL', hex: '#3b82f6' },     // Blue
  { name: 'VERDE', hex: '#10b981' },    // Green
  { name: 'AMARELO', hex: '#f59e0b' },  // Yellow
];

const ColorConflict: React.FC<ColorConflictProps> = ({ onGameOver, onExit }) => {
  const [score, setScore] = useState(0);
  const [timeLeft, setTimeLeft] = useState(60);
  const [currentWord, setCurrentWord] = useState(COLORS[0]);
  const [inkColor, setInkColor] = useState(COLORS[1]);
  const [options, setOptions] = useState(COLORS);

  // Timer
  useEffect(() => {
    if (timeLeft <= 0) {
      onGameOver(score);
      return;
    }
    const timer = setInterval(() => setTimeLeft(t => t - 1), 1000);
    return () => clearInterval(timer);
  }, [timeLeft, onGameOver, score]);

  const generateRound = () => {
    // Random word
    const wordIdx = Math.floor(Math.random() * COLORS.length);
    // Random ink (usually different from word for Stroop effect)
    let inkIdx = Math.floor(Math.random() * COLORS.length);
    // 30% chance they are the same to trick user
    if (Math.random() > 0.7) {
        inkIdx = wordIdx;
    }

    setCurrentWord(COLORS[wordIdx]);
    setInkColor(COLORS[inkIdx]);

    // Shuffle options
    const shuffled = [...COLORS].sort(() => Math.random() - 0.5);
    setOptions(shuffled);
  };

  useEffect(() => {
    generateRound();
  }, []);

  const handleAnswer = (colorHex: string) => {
    // The user must identify the INK COLOR, ignoring the word
    if (colorHex === inkColor.hex) {
      setScore(s => s + 150); // High score for speed
      generateRound();
    } else {
      setScore(s => Math.max(0, s - 50)); // Penalty
      // Optional: shake screen
    }
  };

  return (
    <GameShell
      title="Conflito de Cores"
      description="Selecione a cor da TINTA, ignore a palavra escrita."
      score={score}
      timeLeft={timeLeft}
      onExit={onExit}
    >
      <div className="flex-1 flex flex-col justify-center items-center w-full gap-12">

        {/* The Stimulus */}
        <div className="relative">
          <h2 
            className="text-6xl font-black tracking-wider transition-all duration-300 scale-100 animate-in zoom-in"
            style={{ color: inkColor.hex, textShadow: '0 0 30px rgba(255,255,255,0.1)' }}
          >
            {currentWord.name}
          </h2>
        </div>

        {/* Options */}
        <div className="grid grid-cols-2 gap-4 w-full max-w-sm">
          {options.map((opt) => (
            <button
              key={opt.name}
              onClick={() => handleAnswer(opt.hex)}
              className="h-16 rounded-xl bg-surface border-2 border-white/10 hover:bg-white/5 hover:border-white/20 active:scale-95 transition-all font-bold text-lg tracking-wide"
            >
              {opt.name}
            </button>
          ))}
        </div>
      </div>
    </GameShell>
  );
};

export default ColorConflict;

import React, { useState, useEffect } from 'react';
import GameShell from '../GameShell';

interface QuickMathProps {
  onGameOver: (score: number) => void;
  onExit: () => void;
}

const QuickMath: React.FC<QuickMathProps> = ({ onGameOver, onExit }) => {
  const [score, setScore] = useState(0);
  const [timeLeft, setTimeLeft] = useState(60);
  const [expression, setExpression] = useState("");
  const [correctAnswer, setCorrectAnswer] = useState(0);
  const [options, setOptions] = useState<number[]>([]);

  // Timer
  useEffect(() => {
    if (timeLeft <= 0) {
      onGameOver(score);
      return;
    }
    const timer = setInterval(() => setTimeLeft(t => t - 1), 1000);
    return () => clearInterval(timer);
  }, [timeLeft, onGameOver, score]);

  const generateProblem = () => {
    const ops = ['+', '-', '*'];
    const op = ops[Math.floor(Math.random() * ops.length)];
    let a = 0, b = 0, ans = 0;

    // Adjust difficulty based on score
    const limit = score > 1000 ? 50 : 20;

    switch(op) {
      case '+':
        a = Math.floor(Math.random() * limit) + 1;
        b = Math.floor(Math.random() * limit) + 1;
        ans = a + b;
        break;
      case '-':
        a = Math.floor(Math.random() * limit) + 5;
        b = Math.floor(Math.random() * a); // Ensure positive result
        ans = a - b;
        break;
      case '*':
        a = Math.floor(Math.random() * 12) + 1; // Simple multiplication tables
        b = Math.floor(Math.random() * 9) + 1;
        ans = a * b;
        break;
    }

    setExpression(`${a} ${op} ${b}`);
    setCorrectAnswer(ans);

    // Generate options (1 correct, 3 wrong but close)
    const newOptions = new Set<number>();
    newOptions.add(ans);

    while(newOptions.size < 4) {
      const offset = Math.floor(Math.random() * 10) - 5; // -5 to +5
      const val = ans + offset;
      if (val !== ans && val >= 0) newOptions.add(val);
      // Fallback if loop gets stuck (rare for math)
      if(newOptions.size < 4 && Math.random() > 0.9) newOptions.add(Math.floor(Math.random() * 100));
    }

    setOptions(Array.from(newOptions).sort(() => Math.random() - 0.5));
  };

  useEffect(() => {
    generateProblem();
  }, []);

  const handleAnswer = (val: number) => {
    if (val === correctAnswer) {
      setScore(s => s + 100);
      generateProblem();
    } else {
        // Penalty but no game over
        setScore(s => Math.max(0, s - 50));
    }
  };

  return (
    <GameShell
      title="Matemática Rápida"
      description="Resolva a equação o mais rápido possível."
      score={score}
      timeLeft={timeLeft}
      onExit={onExit}
    >
      <div className="flex-1 flex flex-col justify-center items-center w-full gap-12">
        <div className="text-6xl font-mono font-bold text-white tracking-widest">
          {expression} = ?
        </div>

        <div className="grid grid-cols-2 gap-4 w-full max-w-xs">
          {options.map((opt, i) => (
            <button
              key={i}
              onClick={() => handleAnswer(opt)}
              className="h-20 rounded-2xl bg-surface border border-primary/30 hover:bg-primary/20 hover:border-primary text-2xl font-bold transition-all active:scale-95 text-white"
            >
              {opt}
            </button>
          ))}
        </div>
      </div>
    </GameShell>
  );
};

export default QuickMath;

