import React, { useState, useEffect, useCallback } from 'react';
import GameShell from '../GameShell';

interface LogicGridProps {
  onGameOver: (score: number) => void;
  onExit: () => void;
}

const GRID_SIZE = 3;

const LogicGrid: React.FC<LogicGridProps> = ({ onGameOver, onExit }) => {
  const [level, setLevel] = useState(1);
  const [grid, setGrid] = useState<boolean[]>(Array(GRID_SIZE * GRID_SIZE).fill(false));
  const [moves, setMoves] = useState(0);
  const [timeLeft, setTimeLeft] = useState(90); // 90 seconds total
  const [isTransitioning, setIsTransitioning] = useState(false);

  // Timer
  useEffect(() => {
    if (timeLeft <= 0) {
      onGameOver((level - 1) * 200 + Math.max(0, 100 - moves));
      return;
    }
    const timer = setInterval(() => setTimeLeft(t => t - 1), 1000);
    return () => clearInterval(timer);
  }, [timeLeft, onGameOver, level, moves]);

  // Toggle logic
  const toggleNode = useCallback((index: number, currentGrid: boolean[]) => {
    const newGrid = [...currentGrid];
    const row = Math.floor(index / GRID_SIZE);
    const col = index % GRID_SIZE;

    const toggle = (r: number, c: number) => {
      if (r >= 0 && r < GRID_SIZE && c >= 0 && c < GRID_SIZE) {
        const i = r * GRID_SIZE + c;
        newGrid[i] = !newGrid[i];
      }
    };

    toggle(row, col);     // Self
    toggle(row - 1, col); // Up
    toggle(row + 1, col); // Down
    toggle(row, col - 1); // Left
    toggle(row, col + 1); // Right

    return newGrid;
  }, []);

  // Generate Level
  const generateLevel = useCallback(() => {
    // Start with solved state (all true)
    let newGrid = Array(GRID_SIZE * GRID_SIZE).fill(true);

    // Reverse engineer puzzle by making random valid moves
    // Difficulty increases with level
    const scrambleMoves = level + 3;
    let lastMove = -1;

    for (let i = 0; i < scrambleMoves; i++) {
      let randomIdx;
      do {
        randomIdx = Math.floor(Math.random() * (GRID_SIZE * GRID_SIZE));
      } while (randomIdx === lastMove); // Prevent immediate undo

      newGrid = toggleNode(randomIdx, newGrid);
      lastMove = randomIdx;
    }

    setGrid(newGrid);
    setIsTransitioning(false);
  }, [level, toggleNode]);

  // Initial Load
  useEffect(() => {
    generateLevel();
  }, [generateLevel]);

  const handleNodeClick = (index: number) => {
    if (isTransitioning) return;

    setGrid(prev => {
      const newGrid = toggleNode(index, prev);

      // Check Win Condition immediately after update
      const allActive = newGrid.every(cell => cell === true);

      if (allActive) {
        setIsTransitioning(true);
        setTimeout(() => {
          setLevel(l => l + 1);
          // Add bonus time
          setTimeLeft(t => t + 15);
        }, 500);
      }

      return newGrid;
    });
    setMoves(m => m + 1);
  };

  return (
    <GameShell
      title="Rede Neural"
      description="Ative todos os nós. Clicar em um nó inverte seus vizinhos."
      score={(level - 1) * 100}
      timeLeft={timeLeft}
      onExit={onExit}
    >
      <div className="flex flex-col items-center justify-center flex-1 w-full gap-8">

        <div 
          className="grid gap-4 transition-all duration-500"
          style={{
            gridTemplateColumns: `repeat(${GRID_SIZE}, minmax(0, 1fr))`,
            width: '100%',
            maxWidth: '320px',
            aspectRatio: '1/1'
          }}
        >
          {grid.map((isActive, i) => (
            <button
              key={i}
              onClick={() => handleNodeClick(i)}
              disabled={isTransitioning}
              className={`
                relative rounded-xl transition-all duration-300 border-2
                ${isActive 
                  ? 'bg-accent border-accent shadow-[0_0_20px_rgba(236,72,153,0.6)] scale-100' 
                  : 'bg-surface border-white/10 scale-95 hover:bg-white/5'}
              `}
            >
              {isActive && (
                <div className="absolute inset-0 bg-white/20 animate-pulse rounded-xl" />
              )}
            </button>
          ))}
        </div>

        <div className="bg-surface/50 px-6 py-3 rounded-full border border-white/5">
          <p className="text-sm text-gray-400 font-mono">
            Nível <span className="text-white font-bold text-lg ml-1">{level}</span>
          </p>
        </div>

      </div>
    </GameShell>
  );
};

export default LogicGrid;

import React, { useState } from 'react';
import { GameType, ScreenState, UserStats, GameResult } from './types';
import Dashboard from './components/Dashboard';
import Analysis from './components/Analysis';
import MemoryMatrix from './components/games/MemoryMatrix';
import ColorConflict from './components/games/ColorConflict';
import QuickMath from './components/games/QuickMath';
import LogicGrid from './components/games/LogicGrid';

const INITIAL_STATS: UserStats = {
  streak: 1,
  totalGames: 0,
  history: [],
  categoryScores: {
    [GameType.MEMORY]: 0,
    [GameType.FOCUS]: 0,
    [GameType.LOGIC]: 0,
    [GameType.MATH]: 0
  }
};

const App: React.FC = () => {
  const [currentScreen, setCurrentScreen] = useState<ScreenState>(ScreenState.DASHBOARD);
  const [selectedGame, setSelectedGame] = useState<GameType | null>(null);
  const [userStats, setUserStats] = useState<UserStats>(INITIAL_STATS);

  const handleStartGame = (type: GameType) => {
    setSelectedGame(type);
    setCurrentScreen(ScreenState.PLAYING);
  };

  const handleGameOver = (score: number) => {
    if (!selectedGame) return;

    // Update stats
    setUserStats(prev => {
      const newHistory: GameResult = {
        gameType: selectedGame,
        score,
        date: new Date().toISOString()
      };

      // Calculate normalized score (simple moving average roughly)
      const currentCatScore = prev.categoryScores[selectedGame];
      // Normalize raw score differently per game
      let normalized = 0;
      if (selectedGame === GameType.MEMORY) normalized = Math.min(100, score / 10); // 1000 pts = 100
      if (selectedGame === GameType.FOCUS) normalized = Math.min(100, score / 20); // 2000 pts = 100
      if (selectedGame === GameType.MATH) normalized = Math.min(100, score / 15);
      if (selectedGame === GameType.LOGIC) normalized = Math.min(100, score / 10); // Approx 1000 pts for high level

      const newCatScore = Math.floor((currentCatScore * 0.7) + (normalized * 0.3));

      return {
        ...prev,
        totalGames: prev.totalGames + 1,
        history: [...prev.history, newHistory],
        categoryScores: {
          ...prev.categoryScores,
          [selectedGame]: newCatScore
        }
      };
    });

    setCurrentScreen(ScreenState.DASHBOARD);
    setSelectedGame(null);
  };

  const handleExitGame = () => {
    setCurrentScreen(ScreenState.DASHBOARD);
    setSelectedGame(null);
  };

  const renderScreen = () => {
    switch (currentScreen) {
      case ScreenState.DASHBOARD:
        return (
          <Dashboard 
            onSelectGame={handleStartGame} 
            stats={userStats}
            onAnalyze={() => setCurrentScreen(ScreenState.ANALYSIS)}
          />
        );
      case ScreenState.ANALYSIS:
        return (
          <Analysis 
            history={userStats.history}
            onBack={() => setCurrentScreen(ScreenState.DASHBOARD)}
          />
        );
      case ScreenState.PLAYING:
        switch (selectedGame) {
          case GameType.MEMORY:
            return <MemoryMatrix onGameOver={handleGameOver} onExit={handleExitGame} />;
          case GameType.FOCUS:
            return <ColorConflict onGameOver={handleGameOver} onExit={handleExitGame} />;
          case GameType.MATH:
            return <QuickMath onGameOver={handleGameOver} onExit={handleExitGame} />;
          case GameType.LOGIC:
            return <LogicGrid onGameOver={handleGameOver} onExit={handleExitGame} />;
          default:
            return <div>Jogo não encontrado</div>;
        }
      default:
        return <div>Erro</div>;
    }
  };

  return (
    <div className="min-h-screen bg-background text-white selection:bg-primary selection:text-white">
      {renderScreen()}
    </div>
  );
};

export default App;
